// client/src/pages/CatsPage.js
import React, { useEffect } from 'react';
import { useUser } from '../context/UserContext';
import ResourceBar from '../components/ResourceBar';
import Loading from '../components/Loading';
import CatCard from '../components/CatCard';
import { PawIcon } from '../components/Icons';

const CatsPage = () => {
  const { user, loading, fetchCats, cats } = useUser();

  // Получение кошек пользователя при загрузке страницы
  useEffect(() => {
    if (user) {
      fetchCats();
    }
  }, [user, fetchCats]);

  if (loading || !user) {
    return <Loading />;
  }

  return (
    <div className="pb-16">
      <ResourceBar />

      <div className="pt-16 px-4">
        <div className="flex justify-between items-center mb-4">
          <h1 className="text-2xl font-bold">Ваши кошки</h1>
          <div className="flex items-center text-gray-600">
            <PawIcon className="w-5 h-5 mr-1" />
            <span>{cats.length}</span>
          </div>
        </div>

        {cats && cats.length > 0 ? (
          <>
            {/* Отображение списка кошек с помощью компонента CatCard */}
            {cats.map(cat => (
              <CatCard key={cat._id} cat={cat} />
            ))}
          </>
        ) : (
          <div className="bg-white rounded-lg shadow-md p-4 text-center">
            <p className="mb-2">У вас пока нет кошек</p>
            <p className="text-sm text-gray-600">
              Исследуйте мир, чтобы найти кошек для вашего поселения
            </p>
          </div>
        )}

        {/* Объяснение редкости */}
        <div className="mt-6 bg-gray-50 rounded-lg p-4">
          <h3 className="font-bold mb-2">Редкость кошек:</h3>
          <div className="flex items-center mb-1">
            <div className="w-3 h-3 bg-gray-400 rounded-full mr-2"></div>
            <span className="text-sm">Обычная</span>
          </div>
          <div className="flex items-center mb-1">
            <div className="w-3 h-3 bg-green-500 rounded-full mr-2"></div>
            <span className="text-sm">Необычная</span>
          </div>
          <div className="flex items-center mb-1">
            <div className="w-3 h-3 bg-blue-500 rounded-full mr-2"></div>
            <span className="text-sm">Редкая</span>
          </div>
          <div className="flex items-center mb-1">
            <div className="w-3 h-3 bg-purple-500 rounded-full mr-2"></div>
            <span className="text-sm">Эпическая</span>
          </div>
          <div className="flex items-center">
            <div className="w-3 h-3 bg-yellow-500 rounded-full mr-2"></div>
            <span className="text-sm">Легендарная</span>
          </div>
        </div>
      </div>
    </div>
  );
};

export default CatsPage;
